import React, { Component } from 'react';
import api from '../data/api.js'
import BlogPostCarousel from '../components/blogPostCarousel/blogPostCarousel'

class Home extends Component {
	
	constructor(props) {
		super(props);
		this.state = {
			posts: [],
			isLoading: true,
		}
	}
	
	componentDidMount() {
		api.getPosts()
			.then(posts => {
								if(posts) {
									this.setState({ 
											posts: posts,
											isLoading: false
									})
								};
		})
	}
	
	render() {
		const {isLoading, posts} = this.state;
		
		if(isLoading) {
			return <h3 className='mt-4'>loading...</h3>
		} else 
			return (
				<div>
				 <header className="bg-primary">
        <div className="container h-100">
            <div className="row h-100">
                <div className="col-12">
                    <div className="text-center m-0 vh-100 d-flex flex-column justify-content-center text-light">
                        <h1 className="display-4">Greyson</h1>
                        <p className="lead">Square corners with shades of gray and sea green.</p>
                        <div className="row">
                            <div className="col-lg-4 col-sm-6 mx-auto">
                                <div className="input-group mb-3">
                                  <input type="text" className="form-control form-control-lg" placeholder="your@email"/>
                                  <div className="input-group-append">
                                    <button className="btn btn-outline-light btn-lg rounded-right" type="button">Sign-up</button>
                                  </div>
                                </div>
                            </div>
                        </div>
                        <div className="mt-2 mx-auto">
                             <div className="btn-group">
                                  <a href="theme.css" className="btn btn-outline-light btn-lg">
                                    Download Theme
                                  </a>
                                  <button type="button" className="btn btn-lg btn-outline-light dropdown-toggle dropdown-toggle-split" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false">
                                    <span className="sr-only">Downloads</span>
                                  </button>
                                  <div className="dropdown-menu">
                                      <a className="dropdown-item" href="theme.css">theme.css</a>
                                      <a className="dropdown-item" href="theme.min.css">theme.min.css</a>
                                      <div className="dropdown-divider"></div>
                                      <a className="dropdown-item" href="theme.scss">theme.scss</a>
                                      <div className="dropdown-divider"></div>
                                      <a className="dropdown-item" target="new" href="https://github.com/ThemesGuide/bootstrap-themes/tree/master/greyson">Full template</a>
                                  </div>
                                </div> 
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </header>
				<div className="container">
					<div className='row'>
						<div className='front-image-container col-12'>
							<h2>Heeren A </h2>
							<img src={process.env.PUBLIC_URL + '/background.jpg'} className='p-4' alt="background"/>
						</div>
					</div>
					<div className="row justify-content-center">
						<h2>Laatste posts</h2>
						<div className='row'>
							<BlogPostCarousel posts={posts}/>
						</div>
					</div>
					<div className="row justify-content-center">
						<div>
							<h2>Spelers</h2>
							<p> 
							Bekijk alle top spelers <a href='/team'>hier</a>
							</p>
						</div>
					</div>
					<div className="row justify-content-center">
						<div>
							<h2>Daltons</h2>
							<p> 
								Bekijk alle uitgedeelde en genomen daltons <a href='/daltons'>hier</a>
							</p>
						</div>
					</div>
					</div>
				</div>
				)
			}
	}
    
export default Home


    